package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

public class JsonElementTest {

  // Create a subclass proxy instance of JsonElement that returns true for isJsonArray and getAsJsonArray returns itself
  private JsonElement createJsonArrayProxy() {
    return (JsonElement) Proxy.newProxyInstance(
        JsonArray.class.getClassLoader(),
        new Class<?>[]{JsonArray.class},
        new InvocationHandler() {
          @Override
          public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
            String name = method.getName();
            if ("isJsonArray".equals(name)) {
              return true;
            }
            if ("getAsJsonArray".equals(name)) {
              return proxy;
            }
            // For other methods, throw UnsupportedOperationException to avoid unexpected calls
            throw new UnsupportedOperationException("Method " + name + " not implemented in proxy");
          }
        });
  }

  @Test
  public void testGetAsJsonArray_WhenIsJsonArrayTrue_ReturnsThisAsJsonArray() {
    JsonElement jsonElement = createJsonArrayProxy();
    JsonArray result = jsonElement.getAsJsonArray();
    assertSame(jsonElement, result);
  }

  @Test
  public void testGetAsJsonArray_WhenIsJsonArrayFalse_ThrowsIllegalStateException() {
    JsonElement element = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(element.isJsonArray()).thenReturn(false);
    IllegalStateException exception = assertThrows(IllegalStateException.class, element::getAsJsonArray);
    assertTrue(exception.getMessage().startsWith("Not a JSON Array: "));
  }
}
